import React from "react";

function Deck() {
  return (
    <>
      <button>Create Deck</button>
      <div className="card">
        <h2>{/* deck name */}</h2>
        <p>{/* card count */}</p>
        <h4>{/** deck description */}</h4>
        <button>View</button>
        <button>Study</button>
        <button className="bi bi-trash">Delete</button>
      </div>
    </>
  );
}

export default Deck;
